@startuml
!define SHACL_SHAPE "ex:MyShapemaxCount"
!define SHACL_CODE "@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .\n@prefix schema: <http://schema.org/> .\n@prefix sh: <http://www.w3.org/ns/shacl#> .\n@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .\n@prefix ex: <http://example.org/ns#> .\n\nex:MyShapemaxCount a sh:NodeShape ;\nsh:targetClass ex:Person ;\nsh:property[\n  sh:path ex:age ;\n  sh:maxCount 1 ;\n  sh:datatype xsd:integer ;\n] ."

rectangle "ex:MyShapemaxCount" as shape {
  "age : integer : maxCount[0..1]"
}

note right of shape
  SHACL_CODE
end note

@enduml
